	}
	state := base64.URLEncoding.EncodeToString(b)

	// 2. Determine cookie properties.
	// If a session cookie is provided, we try to match its Domain/Secure settings for consistency,
	// otherwise we default to standard security practices.
	secure := r.TLS != nil
	domain := ""
	if session != nil {
		if session.Secure {
			secure = true
		}
		domain = session.Domain
	}

	// 3. Set the state cookie.
	// This cookie must be verified against the 'state' query param in the callback handler.
	stateCookie := &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		Path:     "/",
		Domain:   domain,
		HttpOnly: true,
		Secure:   secure,
		Expires:  time.Now().Add(15 * time.Minute), // Short expiration for login flow
	}
	http.SetCookie(w, stateCookie)

	// 4. Store the redirectPath in a cookie.
	// The callback handler should read this cookie to know where to send the user after success.
	if redirectPath != "" {
		redirectCookie := &http.Cookie{
			Name:     "next_redirect",
			Value:    redirectPath,
			Path:     "/",
			Domain:   domain,
			HttpOnly: true,
			Secure:   secure,
			Expires:  time.Now().Add(15 * time.Minute),
		}
		http.SetCookie(w, redirectCookie)
	}

	// 5. Generate the OAuth2 URL.
	// AccessTypeOffline is typically requested to receive a refresh token.
	url := OAuthConfig.AuthCodeURL(state, oauth2.AccessTypeOffline)

	return url, nil
}

func main() {
	// Demonstration of usage:

	// Create a dummy request and response recorder
	req := httptest.NewRequest("GET", "http://localhost:8080/login", nil)
	w := httptest.NewRecorder()

	// Optional: Simulate an existing session cookie
	sessionCookie := &http.Cookie{
		Name:  "session_id",
		Value: "xyz123",
	}

	// Call the function
	targetPath := "/dashboard"
	authURL, err := GenerateAuthURL(targetPath, sessionCookie, w, req)
	if err != nil {
		fmt.Printf("Error generating URL: %v\n", err)
		return
	}

	fmt.Println("--- Generated OAuth2 URL ---")
	fmt.Println(authURL)

	fmt.Println("\n--- Cookies Set on Response ---")
	for _, c := range w.Result().Cookies() {
		fmt.Printf("Name: %s, Value: %s\n", c.Name, c.Value)
	}
}

